#include <iostream>
#include <vector>
using namespace std;

int solve(vector<vector<int>> grid) {
    int n = grid.size();
    int m = grid[0].size();
    vector<vector<int>> dp(n + 1, vector<int>(m + 1, 0));
    dp[0][0] = 1;

    int k;
    cin >> k;

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (i + 1 <= n and grid[i + 1][j] == k) {
                dp[i + 1][j] += dp[i][j];
            }
            if (j + 1 <= m and grid[i][j + 1] == k) {
                dp[i][j + 1] += dp[i][j];
            }
        }
    }
    return dp[n][m];
}

int main() {
    int n, k;
    cin >> n >> k;
    vector<vector<int>> grid(n, vector<int>(n, 0));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            cin >> grid[i][j];
        }
    }
    cout << solve(grid) << endl;
    return 0;
}
